EXEC SQL CONNECT TO "connectdb" AS second; 
EXEC SQL CONNECT TO 'connectdb' AS main; 
EXEC SQL CONNECT TO REGRESSDB1 as main; 
EXEC SQL CONNECT TO connectdb AS :id; 
EXEC SQL CONNECT TO connectdb AS main USER connectuser/connectdb; 
EXEC SQL CONNECT TO connectdb AS main USER connectuser USING "connectdb"; 
EXEC SQL CONNECT TO connectdb AS main; 
EXEC SQL CONNECT TO tcp:postgresql://localhost/connectdb USER connectuser IDENTIFIED BY connectpw; 
EXEC SQL CONNECT TO tcp:postgresql://localhost: $PORT /connectdb USER connectuser SQLIDENTIFIED BY connectpw; 
EXEC SQL CONNECT TO unix:postgresql://localhost/connectdb USER connectuser SQLIDENTIFIED BY "connectpw"; 
EXEC SQL CONNECT TO unix:postgresql://localhost/connectdb USER connectuser USING "connectpw"; 使用宿主变量指定连接参数的示例： #include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) 
{ 
EXEC SQL BEGIN DECLARE SECTION; /* 此处dbname、user、pwd应从环境变量或配置文件读取，环境变量需用户自己按需配置；非环境变量情况下可直接赋值字符串 */ char *dbname     = getenv("EXAMPLE_DBNAME_ENV") ;    /* 数据库名 */ 
    char *user       = getenv("EXAMPLE_USERNAME_ENV") ;  /* 连接用户名 */ 
    char *pwd        = getenv("EXAMPLE_PASSWD_ENV") ; /* 密码 */
    char *connection = "tcp:postgresql://localhost: $PORT /testdb";  /* 连接字符串 */ 
    char ver[256];                  /* 存储版本字符串的缓冲区 */ 
EXEC SQL END DECLARE SECTION;

     ECPGdebug(1, stderr); 
     EXEC SQL CONNECT TO :dbname; 
     EXEC SQL SELECT pg_catalog.set_config('search_path', '', false); EXEC SQL COMMIT; 
     EXEC SQL SELECT version() INTO :ver; 
     EXEC SQL DISCONNECT; 

     printf("version: %s\n", ver); 
     EXEC SQL CONNECT TO :connection USER :user USING :pwd; 
     EXEC SQL SELECT pg_catalog.set_config('search_path', '', false); EXEC SQL COMMIT; 
     EXEC SQL SELECT version() INTO :ver; 
     EXEC SQL DISCONNECT; 

     printf("version: %s\n", ver); 
     return 0; 
} 相关链接 DISCONECT ， SET CONNECTION

DECLARE DECLARE 功能描述 声明一个游标用于迭代预备语句的结果集。该命令与SQL命令的DECLARE在语义上略有不同：后者执行查询并准备结果集以便检索，而嵌入式SQL命令只是将一个名称声明为“循环变量”并用于在查询的结果集上迭代，实际在使用OPEN命令打开游标时执行。 语法格式 DECLARE cursor_name [ BINARY ]  [ NO SCROLL ] CURSOR [ { WITH | WITHOUT } HOLD ] FOR prepared_name
DECLARE cursor_name [ BINARY ]  [ NO SCROLL ] CURSOR [ { WITH | WITHOUT } HOLD ] FOR query 参数说明 cursor_name 游标名称，大小写敏感。可以是一个SQL标识符或者一个宿主变量。 prepared_name 预备查询的名称，可以是一个SQL标识符或者一个宿主变量。 query 提供游标要返回的行的SELECT命令。 游标选项的含义参考 DECLARE 。 示例 声明用于查询的游标示例： EXEC SQL DECLARE C CURSOR FOR SELECT * FROM My_Table; 
EXEC SQL DECLARE C CURSOR FOR SELECT Item1 FROM T; 
EXEC SQL DECLARE cur1 CURSOR FOR SELECT version(); 声明用于预备语句的游标示例： EXEC SQL PREPARE stmt1 AS SELECT version(); 
EXEC SQL DECLARE cur1 CURSOR FOR stmt1; 相关链接 OPEN

DESCRIBE DESCRIBE 功能描述 检索预准备语句中包含的结果列的元数据信息。 语法格式 DESCRIBE [ OUTPUT ] prepared_name USING  SQL  DESCRIPTOR descriptor_name
DESCRIBE [ OUTPUT ] prepared_name INTO SQL  DESCRIPTOR descriptor_name
DESCRIBE [ OUTPUT ] prepared_name INTO sqlda_name 参数说明 prepared_name 预备语句名称可以是一个SQL标识符或者宿主变量。 descriptor_name 描述符名称，大小写敏感。可以是SQL标识符或者宿主变量。 sqlda_name SQLDA变量名称，详细使用请参见 SQLDA 。 示例 EXEC SQL ALLOCATE DESCRIPTOR mydesc;
EXEC SQL PREPARE stmt1 FROM :sql_stmt;
EXEC SQL DESCRIBE stmt1 INTO SQL DESCRIPTOR mydesc;
EXEC SQL GET DESCRIPTOR mydesc VALUE 1 :charvar = NAME;
EXEC SQL DEALLOCATE DESCRIPTOR mydesc; 相关链接 ALLOCATE DESCRIPTOR ， GET DESCRIPTOR ，

GET DESCRIPTOR GET DESCRIPTOR 功能描述 检索查询结果集的信息，并且将它存储到宿主变量中。在使用该命令将信息传递给宿主语言变量之前通常使用FETCH或者SELECT填充标识符区域。该命令有两种形式： 检索描述符的“头部”项，适用于全面查看结果集。 列号作为附加参数，检索特定列的信息。 语法格式 GET DESCRIPTOR descriptor_name VALUE column_number :cvariable = descriptor_item [, ... ]
GET DESCRIPTOR descriptor_name:cvariable = descriptor_header_item [, ... ] 参数说明 descriptor_name 描述符名称。 descriptor_header_item 标识要检索哪一个头部项信息。当前仅支持用于得到结果集中列数的COUNT。 column_number 关于被检索的列数信息。计数从1开始。 descriptor_item 标记识别检索列的信息项。 cvariable 宿主变量将接收从描述符区域检索的数据。 示例 检索结果集中列数： EXEC SQL GET DESCRIPTOR d :d_count = COUNT; 在第一列中检索数据长度： EXEC SQL GET DESCRIPTOR d VALUE 1 :d_returned_octet_length = RETURNED_OCTET_LENGTH; 检索作为字符串第二列的数据主体： EXEC SQL GET DESCRIPTOR d VALUE 2 :d_data = DATA; 执行SELECT current_database();并且显示列数、列数据长度和列数据的完整过程示例： #include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) 
{ 
EXEC SQL BEGIN DECLARE SECTION; 
    int  d_count; 
    char d_data[1024]; 
    int  d_returned_octet_length; 
EXEC SQL END DECLARE SECTION; 
    EXEC SQL CONNECT TO testdb AS con1 USER testuser; 
    EXEC SQL SELECT pg_catalog.set_config('search_path', '', false); EXEC SQL COMMIT; 
    EXEC SQL ALLOCATE DESCRIPTOR d; 

    /* 描述、打开一个游标，并且分配一个描述符给该游标  */ 
    EXEC SQL DECLARE cur CURSOR FOR SELECT current_database(); 
    EXEC SQL OPEN cur; 
    EXEC SQL FETCH NEXT FROM cur INTO SQL DESCRIPTOR d; 

    /* 得到全部列的数量 */ 
    EXEC SQL GET DESCRIPTOR d :d_count = COUNT; 
    printf("d_count = %d\n", d_count); 

    /* 得到一个返回列的长度 */ 
    EXEC SQL GET DESCRIPTOR d VALUE 1 :d_returned_octet_length = RETURNED_OCTET_LENGTH; 
    printf("d_returned_octet_length = %d\n", d_returned_octet_length); 

    /* 将返回的列取出成一个字符串 */ 
    EXEC SQL GET DESCRIPTOR d VALUE 1 :d_data = DATA; 
    printf("d_data = %s\n", d_data); 

    /* 关闭 */ 
    EXEC SQL CLOSE cur; 
    EXEC SQL COMMIT; 

    EXEC SQL DEALLOCATE DESCRIPTOR d; 
    EXEC SQL DISCONNECT ALL; 
    return 0; 
} 该示例执行结果为： d_count                 = 1 
d_returned_octet_length = 6 
d_data                  = testdb 相关链接 ALLOCATE DESCRIPTOR ， DEALLOCATE DESCRIPTOR ， SET DESCRIPTOR

VAR VAR 功能描述 将新的C数据类型分配给宿主变量。宿主变量必须预先在声明段声明。 对于VAR的用法需要谨慎。使用VAR语句后数据类型的变化可能会导致内存地址无效，从而导致数据变量无效，出现无法成功赋值的场景。 若在宿主变量声明段中确定好数据类型，则无须使用VAR语句。 语法格式 VAR varname IS ctype 参数说明 varname C语言变量名称。 ctype C语言类型说明。 示例 EXEC SQL BEGIN DECLARE SECTION; 
    short a;
EXEC SQL END DECLARE SECTION;
EXEC SQL VAR a IS int;

OPEN OPEN 功能描述 打开一个游标，并将实际值选择性地绑定到游标声明中的占位符。该游标必须事先使用DECLARE命令声明过。执行OPEN命令会触发在服务器上开始执行查询。 语法格式 OPEN cursor_name
OPEN cursor_name USING value [, ... ] 
OPEN cursor_name USING SQL DESCRIPTOR descriptor_name 参数说明 cursor_name 被打开的游标的名称。可以是一个SQL标识符或者一个宿主变量。 value 被绑定到游标中一个占位符的值。可以是一个SQL常量、一个宿主变量或者一个带有指示符的宿主变量。 descriptor_name 包含要绑定到游标中占位符的值的描述符的名称。可以是一个SQL标识符或者一个宿主变量。 示例 EXEC SQL OPEN a; 
EXEC SQL OPEN d USING 1, 'test'; 
EXEC SQL OPEN c1 USING SQL DESCRIPTOR mydesc; 
EXEC SQL OPEN :curname1; 相关链接 DECLARE

DISCONECT DISCONECT 功能描述 关闭一个（或所有）与数据库的连接。 语法格式 DISCONNECT connection_name
DISCONNECT [ CURRENT ] 
DISCONNECT DEFAULT 
DISCONNECT ALL 参数说明 connection_name 由CONNECT命令建立的数据库连接名称。 current 关闭“当前的”连接，它可以是最近打开的连接或者是由SET CONNECTION命令设置的连接。如果没有参数被传给DISCONNECT命令，它作为默认值。 default 关闭默认连接。 all 关闭所有打开的连接。 示例 #include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) 
{ 
    /* 需要提前创建testdb库 */   
 EXEC SQL CONNECT TO testdb AS DEFAULT USER testuser; 
    EXEC SQL CONNECT TO testdb AS con1 USER testuser; 
    EXEC SQL CONNECT TO testdb AS con2 USER testuser; 
    EXEC SQL CONNECT TO testdb AS con3 USER testuser; 
    EXEC SQL DISCONNECT CURRENT;  /* 关闭 con3          */ 
    EXEC SQL DISCONNECT DEFAULT;  /* 关闭 DEFAULT       */ 
    EXEC SQL DISCONNECT ALL;      /* 关闭 con2 以及 con1 */ 
    return 0; 
} 相关链接 CONNECT ， SET CONNECTION

WHENEVER WHENEVER 功能描述 定义一个行为，它会在SQL执行异常时（行未找到、SQL告警或错误）被调用。 语法格式 WHENEVER { NOT FOUND | SQLERROR | SQLWARNING } action 参数说明 参数描述见 设置回调 章节。 示例 EXEC SQL WHENEVER NOT FOUND CONTINUE; 
EXEC SQL WHENEVER NOT FOUND DO BREAK; 
EXEC SQL WHENEVER SQLWARNING SQLPRINT; 
EXEC SQL WHENEVER SQLWARNING DO warn(); 
EXEC SQL WHENEVER SQLERROR sqlprint; 
EXEC SQL WHENEVER SQLERROR SQLCALL print2(); 
EXEC SQL WHENEVER SQLERROR DO handle_error("select"); 
EXEC SQL WHENEVER SQLERROR DO sqlnotice(NULL, NONO);
EXEC SQL WHENEVER SQLERROR DO sqlprint(); 
EXEC SQL WHENEVER SQLERROR GOTO error_label; 
EXEC SQL WHENEVER SQLERROR STOP; 使用WHENEVER NOT FOUND BREAK来处理结果集的循环，参考如下完整示例： #include <stdlib.h>
#include <string.h>
#include <stdio.h>

int main(void)
{
    EXEC SQL CONNECT TO testdb AS con1;
    EXEC SQL ALLOCATE DESCRIPTOR d;
    EXEC SQL DECLARE cur CURSOR FOR SELECT current_database(), 'hoge', 256;
    EXEC SQL OPEN cur;
    EXEC SQL BEGIN DECLARE SECTION;
    char* d1;
    char* d2;
    EXEC SQL END DECLARE SECTION;
    /* 当到达结果集末尾时，跳出循环 */
    EXEC SQL WHENEVER NOT FOUND DO BREAK;

    while (1)
    {
        EXEC SQL FETCH NEXT FROM cur INTO SQL DESCRIPTOR d;
        exec sql get descriptor d value 1 :d1=DATA;
        exec sql get descriptor d value 2 :d2=DATA;
        printf("d1 is %s,%s\n", d1, d2) ;
    }
     EXEC SQL CLOSE cur;
     EXEC SQL COMMIT;
     EXEC SQL DEALLOCATE DESCRIPTOR d;
     EXEC SQL DISCONNECT ALL;
     return 0;
}
